const WINDOW_MS = 7200000;
const now = Date.now();
// PAT-4 guard: parse the RAW read (pre-filter). Hosted n8n Cloud hands JSON bodies
// back PRE-PARSED (LIVE 2026-07-07) — parse OBJECT-FIRST, never .toString()+parse.
const rows = [];
for (const it of $('Read Heartbeats').all()) {
  const j = it.json || {};
  const body = (function(__b){ if (__b && typeof __b === 'object') return __b; const __s = String(__b ?? '').trim(); if (!__s) return []; try { return JSON.parse(__s); } catch (__e) { return []; } })(j.body);
  if (Array.isArray(body)) rows.push(...body);
  else if (body && typeof body === 'object') rows.push(body);
}
// EMPTY table = the runner has NEVER checked in — that is the loudest failure
// mode, not a pass. ONE distinct alert.
if (rows.length === 0) {
  return [{ json: { __text:
    '🚨 DEAD-MANS SWITCH: no heartbeats at all — the heartbeat table is EMPTY; the runner has never checked in.' } }];
}
const alerts = [];
for (const r of rows) {
  const seen = Date.parse(r.last_seen_at || '') || 0;
  if (seen > now - WINDOW_MS) continue; // fresh — nothing to say
  const mins = Math.round((now - seen) / 60000);
  const who = r.device_id || 'unknown-device';
  alerts.push(seen === 0
    ? '🚨 DEAD-MANS SWITCH: ' + who + ' has no last_seen_at — never checked in.'
    : '🚨 DEAD-MANS SWITCH: ' + who + ' stale — ' + mins + ' min since last heartbeat.');
}
// All fresh ⇒ zero items ⇒ the Telegram node does not run. Silence = healthy.
return alerts.map((a) => ({ json: { __text: a } }));
